#!/usr/bin/env python3
# apply_bookfair_icon.py — Book Fair map node icon (a932, transparent PNG, no white bg).
# Usage from repo root:  python3 apply_bookfair_icon.py  &&  python3 build.py
import json, os, sys
root=os.path.dirname(os.path.abspath(__file__)); AJ=os.path.join(root,"assets","assets.json")
NEW={"a932": ""}
if not os.path.exists(AJ): sys.exit("[apply] assets/assets.json not found - run from repo root.")
x=json.load(open(AJ))
def raw_only(v):
    i=v.find('base64,'); return v[i+7:] if i!=-1 else v
ch=[]
for k,v in NEW.items():
    nv=raw_only(v)
    if x.get(k)!=nv: x[k]=nv; ch.append(k)
json.dump(x,open(AJ,"w")); print(f"[apply] book fair icon -> {ch}"); print("[apply] done. Next: python3 build.py")
